    public EmployeeStatusResponse getEmployeeStatus(
            @WebParam(name = "employeeId") long employeeId) {

        EmployeeStatusResponse response = new EmployeeStatusResponse();
        EmployeeRecord employee = EMPLOYEES.get(employeeId);

        if (employee == null) {
            response.setSuccess(false);
            response.setMessage("Employee not found");
            return response;
        }

        response.setSuccess(true);
        response.setMessage("Employee retrieved successfully");
        response.setEmployeeId(employee.getEmployeeId());
        response.setEmployeeName(employee.getName());
        response.setDepartment(employee.getDepartment());
        response.setSalary(employee.getSalary());
        response.setStatus(employee.getStatus());
        response.setLastSalaryUpdateDate(employee.getLastSalaryUpdateDate());
        response.setLastReviewDate(employee.getLastReviewDate());
        response.setTerminationDate(employee.getTerminationDate());
        return response;
    }

